import json, re
import pandas as pd

with open(var_call_ivRvrB6C6c4E1YIc1nGaYvPo, 'r') as f:
    funding = json.load(f)
fund_df = pd.DataFrame(funding)
fund_df['total_amount'] = pd.to_numeric(fund_df['total_amount'], errors='coerce').fillna(0).astype(int)
fund_map = dict(zip(fund_df['Project_Name'], fund_df['total_amount']))

with open(var_call_8fkncmUqzr1w9RAFHBU5aXKQ, 'r') as f:
    docs = json.load(f)

begin_pat = re.compile('Begin\\s+Construction\\s*:\\s*([^\\n\\r]+)', re.IGNORECASE)
proj_line_pat = re.compile('^\\s*([A-Z0-9][A-Za-z0-9].{3,120})\\s*$')

bad_prefixes = ['(cid:', 'Page', 'Agenda Item', 'RECOMMENDED', 'DISCUSSION', 'Subject', 'To:', 'Prepared by', 'Approved by', 'Date prepared', 'Meeting date']

def looks_like_project(name):
    n = name.strip()
    if len(n) < 5 or len(n) > 120:
        return False
    for bp in bad_prefixes:
        if n.startswith(bp):
            return False
    low = n.lower()
    if ('begin construction' in low) or ('complete design' in low) or ('advertise' in low):
        return False
    if n.endswith('.') and '(' not in n:
        return False
    if re.search('\\((fema|caloes|caljpia).*?\\)', low):
        return True
    if 'project' in low:
        return True
    if any(k in low for k in ['road','canyon','storm','drain','guardrail','sirens','warning','culvert','bridge','slope','retaining','fire']):
        return True
    return False

projects = set()

for d in docs:
    lines = d.get('text','').splitlines()
    in_disaster = False
    current = None
    for i, line in enumerate(lines):
        if re.search('^\\s*Disaster\\s+Projects', line, re.IGNORECASE) or re.search('^\\s*Disaster\\s+Recovery\\s+Projects', line, re.IGNORECASE):
            in_disaster = True
            current = None
            continue
        if in_disaster and re.search('^\\s*Capital\\s+Improvement\\s+Projects', line, re.IGNORECASE):
            in_disaster = False
            current = None
            continue
        if not in_disaster:
            continue

        m = proj_line_pat.match(line)
        if m:
            cand = m.group(1).strip()
            if looks_like_project(cand):
                ahead_lines = [l.strip() for l in lines[i+1:i+4]]
                ahead = '\\n'.join(ahead_lines)
                if re.search('Updates', ahead, re.IGNORECASE) or re.search('Project Schedule', ahead, re.IGNORECASE) or re.search('Estimated Schedule', ahead, re.IGNORECASE):
                    current = cand
                    continue

        bm = begin_pat.search(line)
        if bm and current:
            if '2022' in bm.group(1):
                projects.add(current)

missing = []
total = 0
for p in sorted(projects):
    if p in fund_map:
        total += int(fund_map[p])
    else:
        missing.append(p)

out = {
    'projects_started_2022_disaster': sorted(projects),
    'project_count': len(projects),
    'total_funding': total,
    'missing_in_funding_table': missing
}

print('__RESULT__:')
print(json.dumps(out))

